package ua.university.sms.service;
import org.junit.jupiter.api.*;import org.springframework.beans.factory.annotation.Autowired;import org.springframework.boot.test.context.SpringBootTest;import ua.university.sms.model.dto.StudentDtos;import ua.university.sms.model.entity.StudentStatus;import static org.junit.jupiter.api.Assertions.*;
@SpringBootTest class StudentServiceTest{@Autowired StudentService service;@Test void createsStudent(){var r=service.create(new StudentDtos.Request("Test Student","test.student@mail.com",1,StudentStatus.ACTIVE));assertNotNull(r.id());assertEquals("Test Student",r.fullName());}@Test void filtersByStatus(){assertFalse(service.list(StudentStatus.ACTIVE,null,null).isEmpty());}@Test void filtersByYear(){assertFalse(service.list(null,2,null).isEmpty());}@Test void searchesByEmail(){assertFalse(service.list(null,null,"student.ua").isEmpty());}@Test void returnsTopStudents(){assertFalse(service.top(3).isEmpty());}@Test void returnsUnpaidStudents(){assertFalse(service.unpaid().isEmpty());}}
